function vpcode = getVpCode(exptstr,vpnr)%% asks for subject-ID% input: exptstr (string) name of experiment % % 2006 by Martin Rolfsif nargin==1	FlushEvents('keyDown');% 	vpnr = input('>>>> Subject code [e.g., EG01]:  ','s');	if length(vpnr)==1		vpnr = strcat('0',vpnr);	end		if ~ischar(exptstr) || isempty(vpnr)		vpcode = sprintf(strcat(exptstr,'test'));	else		vpcode = sprintf(strcat(exptstr,'_%s'),vpnr);	endelse	fprintf(1, 'use 1 string argument during call to getVpCode\n');	vpcode=NaN;end